import React, { useState, useEffect } from 'react';

const defaultCategories = [
  { id: 'btech', label: 'B.Tech', badge: 'DEGREE', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering'] },
  { id: 'bdes', label: 'B.Des', badge: 'DESIGN', color: 'border-yellow-500', bgColor: 'bg-yellow-500', lightBg: 'bg-yellow-50', programs: ['Product Design', 'Interior Design'] }
];

export default function AdminCategories({ confirmDelete, CenterModal }) {
  const [categories, setCategories] = useState([]);
  const [catForm, setCatForm] = useState({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });

  // Program Details Editing
  const [programData, setProgramData] = useState({});
  const [selectedProgramEdit, setSelectedProgramEdit] = useState('');
  const [jsonInput, setJsonInput] = useState('');
  const [jsonError, setJsonError] = useState('');

  useEffect(() => {
    const loadCategories = () => {
      const storedCat = localStorage.getItem('indus_categories');
      setCategories(storedCat ? JSON.parse(storedCat) : defaultCategories);
    };

    // Initial load
    loadCategories();

    const storedProg = localStorage.getItem('indus_programData');
    setProgramData(storedProg ? JSON.parse(storedProg) : {});

    // Listen for cross-component storage updates (like from Admin.js confirmDelete)
    window.addEventListener('storage', loadCategories);
    return () => window.removeEventListener('storage', loadCategories);
  }, []);

  const saveCats = (data) => {
    setCategories(data);
    localStorage.setItem('indus_categories', JSON.stringify(data));
  };
  const saveProgData = (data) => {
    setProgramData(data);
    localStorage.setItem('indus_programData', JSON.stringify(data));
  };

  const saveCategory = (e) => {
    e.preventDefault();
    const id = catForm.id || catForm.label.toLowerCase().replace(/\s+/g, '-');
    const existing = categories.findIndex(c => c.id === id);
    const newCat = {
      ...catForm,
      id,
      programs: typeof catForm.programs === 'string' ? catForm.programs.split(',').map(s => s.trim()).filter(p => p) : catForm.programs
    };

    if (existing >= 0) {
      const updated = [...categories];
      updated[existing] = newCat;
      saveCats(updated);
    } else {
      saveCats([...categories, newCat]);
    }
    setCatForm({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });
  };

  const handleProgramSelect = (prog) => {
    setSelectedProgramEdit(prog);
    const data = programData[prog] || { 'CURRICULUM & LEARNING': { sections: [{ title: 'Overview', items: ['Point 1'] }] } };
    setJsonInput(JSON.stringify(data, null, 2));
    setJsonError('');
  };

  const handleJsonSave = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      setJsonError('');
      saveProgData({ ...programData, [selectedProgramEdit]: parsed });
      alert('Program details updated successfully!');
      setSelectedProgramEdit('');
    } catch(err) {
      setJsonError('Invalid JSON format: ' + err.message);
    }
  };

  return (
    <div className="space-y-12 fade-in">
      {/* Category Editor */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col lg:flex-row gap-10">
        <div className="lg:w-1/3">
          <h3 className="text-2xl font-black mb-6 text-slate-800">{catForm.id ? 'Edit Category' : 'Create Category'}</h3>
          <form onSubmit={saveCategory} className="space-y-4">
            <div>
              <label className="block text-[10px] font-black uppercase text-slate-400 mb-1">Label (e.g. B.Tech)</label>
              <input required type="text" value={catForm.label} onChange={e => setCatForm({...catForm, label: e.target.value})} className="w-full bg-slate-50 p-3 rounded-lg outline-none font-bold" />
            </div>
            <div>
              <label className="block text-[10px] font-black uppercase text-slate-400 mb-1">Badge (e.g. DEGREE)</label>
              <input required type="text" value={catForm.badge} onChange={e => setCatForm({...catForm, badge: e.target.value})} className="w-full bg-slate-50 p-3 rounded-lg outline-none font-bold uppercase" />
            </div>
            <div>
              <label className="block text-[10px] font-black uppercase text-slate-400 mb-1">Programs (comma separated)</label>
              <textarea placeholder="Civil Engineering, Mechanical Engineering..." value={typeof catForm.programs === 'string' ? catForm.programs : catForm.programs.join(', ')} onChange={e => setCatForm({...catForm, programs: e.target.value})} className="w-full bg-slate-50 p-3 rounded-lg outline-none font-bold min-h-[100px]"></textarea>
            </div>
            <div className="pt-2 flex gap-2">
              <button type="submit" className="flex-1 bg-[#1a56db] text-white font-bold py-3 rounded-lg hover:bg-blue-800 transition">Save Category</button>
              {catForm.id && <button type="button" onClick={() => setCatForm({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' })} className="px-4 bg-slate-200 rounded-lg font-bold text-slate-600">Cancel</button>}
            </div>
          </form>
        </div>

        <div className="lg:w-2/3 border-l-2 border-slate-50 pl-10 space-y-4">
          <h3 className="text-xl font-black text-slate-800 mb-4">Active Categories</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {categories.map((cat, idx) => (
              <div key={cat.id} className="bg-slate-50 border border-slate-100 p-5 rounded-2xl relative group">
                <div className="text-[10px] uppercase font-black text-slate-400 tracking-wider mix-blend-color-burn">{cat.badge}</div>
                <h4 className="text-xl font-black text-slate-900">{cat.label}</h4>
                <p className="text-xs font-bold mt-2 text-slate-500 truncate">{cat.programs.join(', ')}</p>
                <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => setCatForm(cat)} className="text-[#1a56db] font-bold text-sm bg-blue-100 px-3 py-1 rounded">Edit</button>
                  <button onClick={() => confirmDelete('category', cat.id, cat.label)} className="text-red-600 font-bold text-sm bg-red-100 px-3 py-1 rounded">Del</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Program Details JSON Editor */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
        <h3 className="text-2xl font-black mb-2 text-slate-800 border-l-4 border-[#ff4d20] pl-4">Program Details Advanced Editor</h3>
        <p className="text-sm font-bold text-slate-500 mb-8 pl-5">Select a program to configure its detailed popup information (JSON Format).</p>

        {!selectedProgramEdit ? (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 max-h-[300px] overflow-y-auto">
             {categories.flatMap(c => c.programs).filter((v, i, a) => a.indexOf(v) === i).sort().map(prog => (
               <button key={prog} onClick={() => handleProgramSelect(prog)} className="text-left bg-slate-50 hover:bg-slate-100 p-4 rounded-xl border border-slate-100 text-sm font-bold text-slate-700 hover:text-brand-brown transition-colors truncate">
                 {prog}
               </button>
             ))}
          </div>
        ) : (
          <div className="space-y-4 fade-in">
             <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl">
               <div>
                  <span className="text-[10px] font-black uppercase text-slate-400">Editing Program Data FOR</span>
                  <h4 className="text-xl font-black text-slate-900">{selectedProgramEdit}</h4>
               </div>
               <button onClick={() => setSelectedProgramEdit('')} className="bg-white border rounded px-4 py-2 font-bold text-sm shadow-sm">Back to List</button>
             </div>

             <div className="relative">
               <textarea 
                  value={jsonInput} 
                  onChange={e => setJsonInput(e.target.value)} 
                  className="w-full bg-[#1e1e1e] text-[#d4d4d4] font-mono text-sm p-6 rounded-2xl min-h-[400px] shadow-inner focus:outline-none focus:ring-4 ring-brand-brown/30"
                  spellCheck={false}
               ></textarea>
               {jsonError && <div className="absolute bottom-4 left-4 right-4 bg-red-500/90 text-white text-xs font-bold p-3 rounded border border-red-400">{jsonError}</div>}
             </div>

             <button onClick={handleJsonSave} className="w-full bg-[#ff4d20] text-white font-black py-4 rounded-xl hover:scale-[1.01] transition-transform">Valdate & Save Program Data</button>
          </div>
        )}
      </div>

    </div>
  );
}
